 83: export const verifyAuditChain = async () => {
 84:   const rows = await listAuditLogsByIdAsc();
 85:   const failures: Array<{ id: number; reason: string }> = [];
 86: 
 87:   let previousHash: string | null = null;
 88:   for (const row of rows) {
 89:     if (row.previousHash !== previousHash) {
 90:       failures.push({ id: row.id, reason: 'PREVIOUS_HASH_MISMATCH' });
 91:     }
 92: 
 93:     const expectedCurrent = buildHash(row.previousHash, row.hashBasis);
 94:     if (row.currentHash !== expectedCurrent) {
 95:       failures.push({ id: row.id, reason: 'CURRENT_HASH_INVALID' });
 96:     }
 97: 
 98:     previousHash = row.currentHash;
 99:   }
100: 
101:   return {
102:     total: rows.length,
103:     valid: failures.length === 0,
104:     failures
105:   };
106: };

