  45:         resourceId: event.resourceId,
  46:         clientRecordedAt: new Date().toISOString(),
  47:         metadata: event.payload,
  48:       },
  49:     ],
  50:   };
  51: 
  52:   try {
  53:     await apiRequest("/behavior/events", {
  54:       method: "POST",
  55:       body: JSON.stringify(requestBody),
  56:     });
  57:   } catch {
  58:     // Telemetry should never block user flows.
  59:   }
  60: };

