  1: import { dbPool } from '../../../db/pool';
  2: import type { BehaviorEventInput, BehaviorSummaryRow } from '../types';
  3: 
  4: export const insertDedupKey = async (params: {
  5:   idempotencyKey: string;
  6:   eventType: string;
  7:   userId: number | null;
  8: }): Promise<boolean> => {
  9:   const [result] = await dbPool.query<any>(
 10:     `INSERT IGNORE INTO behavior_ingestion_dedup_keys (idempotency_key, event_type, user_id)
 11:      VALUES (?, ?, ?)`,
 12:     [params.idempotencyKey, params.eventType, params.userId]
 13:   );
 14: 
 15:   return Number(result.affectedRows ?? 0) > 0;
 16: };
 17: 
 18: export const insertBehaviorQueue = async (params: {
 19:   idempotencyKey: string;
 20:   payload: Record<string, unknown>;
 21: }): Promise<void> => {
 22:   await dbPool.query(
 23:     `INSERT INTO behavior_ingestion_queue (idempotency_key, payload_json, status)
 24:      VALUES (?, ?, 'PENDING')`,
 25:     [params.idempotencyKey, JSON.stringify(params.payload)]
 26:   );
 27: };
 28: 
 29: export const listPendingBehaviorQueueItems = async (limit: number): Promise<
 30:   Array<{
 31:     id: number;
 32:     payloadJson: unknown;
 33:     retryCount: number;
 34:   }>
 35: > => {
 36:   const [rows] = await dbPool.query<
 37:     Array<{ id: number; payload_json: unknown; retry_count: number }>
 38:   >(
 39:     `SELECT id, payload_json, retry_count
 40:      FROM behavior_ingestion_queue
 41:      WHERE status = 'PENDING'
 42:        AND available_at <= UTC_TIMESTAMP()
 43:      ORDER BY id ASC
 44:      LIMIT ?`,
 45:     [limit]
 46:   );
 47: 
 48:   return rows.map((row) => ({
 49:     id: row.id,
 50:     payloadJson: row.payload_json,
 51:     retryCount: Number(row.retry_count)
 52:   }));
 53: };
 54: 
 55: export const markBehaviorQueueProcessed = async (queueId: number): Promise<void> => {
 56:   await dbPool.query(
 57:     `UPDATE behavior_ingestion_queue
 58:      SET status = 'PROCESSED',
 59:          processed_at = CURRENT_TIMESTAMP,
 60:          last_error = NULL
 61:      WHERE id = ?`,
 62:     [queueId]
 63:   );
 64: };
 65: 
 66: export const markBehaviorQueueFailed = async (params: {
 67:   queueId: number;
 68:   retryCount: number;
 69:   errorMessage: string;
 70:   maxRetries: number;
 71: }): Promise<void> => {
 72:   const nextRetryCount = params.retryCount + 1;
 73: 
 74:   if (nextRetryCount >= params.maxRetries) {
 75:     await dbPool.query(
 76:       `UPDATE behavior_ingestion_queue
 77:        SET status = 'FAILED',
 78:            retry_count = ?,
 79:            last_error = ?,
 80:            processed_at = CURRENT_TIMESTAMP
 81:        WHERE id = ?`,
 82:       [nextRetryCount, params.errorMessage.slice(0, 255), params.queueId]
 83:     );
 84:     return;
 85:   }
 86: 
 87:   const delaySeconds = Math.min(300, Math.pow(2, nextRetryCount));
 88:   await dbPool.query(
 89:     `UPDATE behavior_ingestion_queue
 90:      SET status = 'PENDING',
 91:          retry_count = ?,
 92:          last_error = ?,
 93:          available_at = DATE_ADD(UTC_TIMESTAMP(), INTERVAL ? SECOND)
 94:      WHERE id = ?`,
 95:     [nextRetryCount, params.errorMessage.slice(0, 255), delaySeconds, params.queueId]
 96:   );
 97: };
 98: 
 99: export const insertBehaviorHotEvent = async (params: {
100:   userId: number | null;
101:   event: BehaviorEventInput;
102: }): Promise<void> => {
103:   await dbPool.query(
104:     `INSERT INTO behavior_events_hot
105:       (idempotency_key, event_type, user_id, resource_type, resource_id, client_recorded_at, metadata_json)
106:      VALUES (?, ?, ?, ?, ?, ?, ?)`,
107:     [
108:       params.event.idempotencyKey,
109:       params.event.eventType,
110:       params.userId,
111:       params.event.resourceType,
112:       params.event.resourceId ?? null,
113:       params.event.clientRecordedAt ?? null,
114:       params.event.metadata ? JSON.stringify(params.event.metadata) : null
115:     ]
116:   );
117: };
118: 
119: export const getBehaviorSummaryRows = async (params: {
120:   from?: string;
121:   to?: string;
122: }): Promise<BehaviorSummaryRow[]> => {
123:   const filters: string[] = [];
124:   const values: string[] = [];
125: 
126:   if (params.from) {
127:     filters.push('server_recorded_at >= ?');
128:     values.push(`${params.from} 00:00:00`);
129:   }
130:   if (params.to) {
131:     filters.push('server_recorded_at <= ?');
132:     values.push(`${params.to} 23:59:59`);
133:   }
134: 
