 24:   const lines = params.items.map((item) => {
 25:     const record = listingMap.get(item.listingId);
 26:     if (!record) {
 27:       throw new Error(`Listing ${item.listingId} not available for pricing.`);
 28:     }
 29: 
 30:     const quantity = item.quantity;
