 32: 
 33:     let subtotal = roundMoney(unitPrice * quantity);
 34:     let memberPricingAdjustment = 0;
 35:     let tieredDiscount = 0;
 36:     let cappedDiscount = 0;
 37:     let subsidy = 0;
 38: 
 39:     const appliedRules: Array<{
 40:       code: string;
 41:       ruleType: PricingRuleType;
 42:       value: number;
 43:       details: Record<string, unknown>;
 44:     }> = [];
 45: 
 46:     for (const rule of params.ruleVersions) {
 47:       if (rule.ruleType === 'MEMBER_PRICING' && rule.config.memberUnitPrice !== undefined) {
 48:         const targetSubtotal = roundMoney(rule.config.memberUnitPrice * quantity);
 49:         const adjustment = roundMoney(subtotal - targetSubtotal);
 50:         if (adjustment > 0) {
 51:           memberPricingAdjustment += adjustment;
 52:           subtotal = targetSubtotal;
