 54:             code: rule.code,
 55:             ruleType: rule.ruleType,
 56:             value: adjustment,
 57:             details: { memberUnitPrice: rule.config.memberUnitPrice }
 58:           });
 59:         }
 60:       }
 61: 
 62:       if (rule.ruleType === 'TIERED_DISCOUNT') {
 63:         const minQuantity = Number(rule.config.minQuantity ?? 0);
 64:         const percent = Number(rule.config.percent ?? 0);
 65:         if (quantity >= minQuantity && percent > 0) {
 66:           const discount = roundMoney(subtotal * percent);
 67:           tieredDiscount += discount;
 68:           appliedRules.push({
 69:             code: rule.code,
 70:             ruleType: rule.ruleType,
 71:             value: discount,
 72:             details: { minQuantity, percent }
 73:           });
 74:         }
 75:       }
 76: 
 77:       if (rule.ruleType === 'CAPPED_DISCOUNT') {
 78:         const percent = Number(rule.config.percent ?? 0);
 79:         const maxDiscount = Number(rule.config.maxDiscount ?? 0);
 80:         if (percent > 0 && maxDiscount > 0) {
 81:           const discount = Math.min(roundMoney(subtotal * percent), maxDiscount);
 82:           cappedDiscount += roundMoney(discount);
 83:           appliedRules.push({
 84:             code: rule.code,
 85:             ruleType: rule.ruleType,
 86:             value: roundMoney(discount),
 87:             details: { percent, maxDiscount }
 88:           });
