 319: export const updateBlacklistEntry = async (params: {
 320:   id: number;
 321:   reason?: string;
 322:   active?: boolean;
 323: }): Promise<boolean> => {
 324:   const updates: string[] = [];
 325:   const queryParams: Array<string | number> = [];
 326: 
 327:   if (typeof params.reason === "string") {
 328:     updates.push("reason = ?");
 329:     queryParams.push(params.reason);
 330:   }
 331: 
 332:   if (typeof params.active === "boolean") {
 333:     updates.push("active = ?");
 334:     queryParams.push(params.active ? 1 : 0);
 335:   }
 336: 
 337:   if (updates.length === 0) {
 338:     return false;
 339:   }
 340: 
 341:   queryParams.push(params.id);
 342: 
 343:   const [result] = await dbPool.query<any>(
 344:     `UPDATE withdrawal_blacklist
 345:      SET ${updates.join(", ")},
 346:          updated_at = CURRENT_TIMESTAMP
 347:      WHERE id = ?`,
 348:     queryParams,
 349:   );
 350: 
 351:   return Number(result.affectedRows ?? 0) > 0;
 352: };
