import { createThreadComment, getThreadComments } from '../../src/features/discussions/services/discussionService';
import * as repo from '../../src/features/discussions/repositories/discussionRepository';

vi.mock('../../src/features/discussions/repositories/discussionRepository');

const mockedRepo = vi.mocked(repo);

describe('discussion service', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('generates mention notifications when @username is present', async () => {
    mockedRepo.isOrderOwnedByUser.mockResolvedValue(true);
    mockedRepo.getOrCreateDiscussion.mockResolvedValue({
      id: 100,
      contextType: 'LISTING',
      contextId: 5
    });
    mockedRepo.createComment.mockResolvedValue({ commentId: 200 });
    mockedRepo.findUsersByUsernames.mockResolvedValue([
      { id: 12, username: 'leader1' },
      { id: 13, username: 'reviewer1' }
    ]);
    mockedRepo.createCommentMentions.mockResolvedValue();
    mockedRepo.createNotification.mockResolvedValue();

    const result = await createThreadComment({
      input: {
        contextType: 'LISTING',
        contextId: 5,
        body: 'Please check this @leader1 and @reviewer1'
      },
      userId: 1,
      username: 'member1',
      roles: ['MEMBER']
    });

    expect(result.commentId).toBe(200);
    expect(mockedRepo.createCommentMentions).toHaveBeenCalledWith({
      commentId: 200,
      mentions: [
        { userId: 12, username: 'leader1' },
        { userId: 13, username: 'reviewer1' }
      ]
    });
    expect(mockedRepo.createNotification).toHaveBeenCalledTimes(2);
  });

  it('returns fixed page size 20 for thread response', async () => {
    mockedRepo.getDiscussionById.mockResolvedValue({
      id: 100,
      contextType: 'ORDER',
      contextId: 44
    });
    mockedRepo.getThreadCommentsPage.mockResolvedValue({
      total: 31,
      comments: []
    });

    const page = await getThreadComments({
      discussionId: 100,
      page: 2,
      sort: 'newest',
      userId: 1,
      roles: ['REVIEWER']
    });

    expect(page?.pageSize).toBe(20);
    expect(page?.page).toBe(2);
  });

  it('blocks member access to order thread they do not own', async () => {
    mockedRepo.getDiscussionById.mockResolvedValue({
      id: 101,
      contextType: 'ORDER',
      contextId: 77
    });
    mockedRepo.isOrderOwnedByUser.mockResolvedValue(false);

    await expect(
      getThreadComments({
        discussionId: 101,
        page: 1,
        sort: 'newest',
        userId: 9,
        roles: ['MEMBER']
      })
    ).rejects.toThrow('THREAD_FORBIDDEN');
  });

  it('allows privileged role access to order thread without ownership', async () => {
    mockedRepo.getDiscussionById.mockResolvedValue({
      id: 102,
      contextType: 'ORDER',
      contextId: 88
    });
    mockedRepo.getThreadCommentsPage.mockResolvedValue({
      total: 1,
      comments: []
    });

    await getThreadComments({
      discussionId: 102,
      page: 1,
      sort: 'newest',
      userId: 14,
      roles: ['REVIEWER']
    });

    expect(mockedRepo.isOrderOwnedByUser).not.toHaveBeenCalled();
    expect(mockedRepo.getThreadCommentsPage).toHaveBeenCalled();
  });
});

import { afterEach, describe, expect, it, vi } from "vitest";

import { ApiError, apiRequest } from "../src/api/client";

const mockFetch = vi.fn<typeof fetch>();

vi.stubGlobal("fetch", mockFetch);

const mockJsonResponse = (payload: unknown, status = 200): Response => {
  const body = JSON.stringify(payload);
  return {
    ok: status >= 200 && status < 300,
    status,
    headers: {
      get: (name: string) =>
        name.toLowerCase() === "content-type" ? "application/json" : null,
    } as Headers,
    text: async () => body,
  } as unknown as Response;
};

afterEach(() => {
  mockFetch.mockReset();
});

describe("ApiError", () => {
  it("captures status and payload", () => {
    const payload = { error: "bad request" };
    const error = new ApiError("Request failed", 400, payload);

    expect(error.message).toBe("Request failed");
    expect(error.status).toBe(400);
    expect(error.payload).toEqual(payload);
  });
});

describe("apiRequest", () => {
  it("returns plain JSON payloads for legacy endpoints", async () => {
    mockFetch.mockResolvedValueOnce(mockJsonResponse({ user: { id: 1 } }));

    const payload = await apiRequest<{ user: { id: number } }>("/auth/me");
    expect(payload.user.id).toBe(1);
  });

  it("parses wrapped success responses", async () => {
    mockFetch.mockResolvedValueOnce(
      mockJsonResponse({ success: true, data: { ok: true } }),
    );

    const payload = await apiRequest<{
      success: boolean;
      data: { ok: boolean };
    }>("/health");
    expect(payload.success).toBe(true);
    expect(payload.data.ok).toBe(true);
  });

  it("extracts wrapped error messages", async () => {
    mockFetch.mockResolvedValueOnce(
      mockJsonResponse(
        {
          success: false,
          error: { code: "NOT_AUTHENTICATED", message: "Not authenticated." },
        },
        401,
      ),
    );

    await expect(apiRequest("/auth/me")).rejects.toThrow(
      /Your session has expired\./,
    );
  });

  it("returns descriptive network error when fetch fails", async () => {
    mockFetch.mockRejectedValueOnce(new Error("socket hang up"));

    await expect(apiRequest("/auth/login")).rejects.toThrow(
      /Unable to reach the server\./,
    );
  });
});

